INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 2, 1, 1000, 2, "vo_minigame_1013_icon_1_002_001", 3000, "vo_minigame_1013_icon_2_002_001", "訓練はまだ\nここからですわ", "調子が上がって\nきたなっ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 2, 2, 5000, 2, "vo_minigame_1013_icon_1_003_001", 3000, "vo_minigame_1013_icon_2_003_001", "クスクス、悪くない\n流れですわね", "ほらほら、\nまだいけるだろ？");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 3, 3, 10000, 2, "vo_minigame_1013_icon_1_004_001", 3000, "vo_minigame_1013_icon_2_004_001", "すばらしい\n記録ですわ", "へへっ、おまえら\nやるじゃねえか！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 3, 4, 10000, 3, "vo_minigame_1013_icon_1_005_001", 3000, "vo_minigame_1013_icon_2_005_001", "乗りに乗って\nいますわね", "あたしたちはまだ\n止まらねえぜ！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 3, 5, 10000, 3, "vo_minigame_1013_icon_1_005_002", 3000, "vo_minigame_1013_icon_2_005_002", "まだまだ行きます\nついてきなさい", "見てろよ！\nマコト班の快進撃だ！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 3, 6, 10000, 3, "vo_minigame_1013_icon_1_005_003", 3000, "vo_minigame_1013_icon_2_005_003", "エリコ班の\n本領発揮ですわ！", "うおぉぉっ！\n絶好調だぜ！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, 3, 7, 0, 4, "vo_minigame_1013_icon_1_006_001", 3000, "vo_minigame_1013_icon_2_006_001", "ここからは\n前人未到の領域です！", "どこまで行けるか\n楽しみだなっ！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 4, 8, 1, 5, "vo_minigame_1013_icon_1_007_001", 1000, "vo_minigame_1013_icon_2_007_001", "厄介でしたわ…", "まだ諦めんなよっ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 4, 9, 1, 5, "vo_minigame_1013_icon_1_007_002", 1000, "vo_minigame_1013_icon_2_007_002", "油断大敵です", "冷やっとしたぜ…！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, 4, 10, 1, 5, "vo_minigame_1013_icon_1_007_003", 1000, "vo_minigame_1013_icon_2_007_003", "忌々しいっ…", "弱音を吐くなっ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (4, 3, 11, 99, 6, "vo_minigame_1013_icon_1_008_001", 1500, "vo_minigame_1013_icon_2_008_001", "大所帯ですわね", "マコト班集合！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (4, 3, 12, 99, 6, "vo_minigame_1013_icon_1_008_002", 1500, "vo_minigame_1013_icon_2_008_002", "エリコ班へようこそ", "連携してくぞ！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (1, 6, 13, 0, 8, "vo_minigame_1013_icon_1_020_001", 3000, "vo_minigame_1013_icon_2_020_001", "ナナカちゃんに\nお任せあれ", "みんなに力を！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (1, 7, 14, 0, 9, "vo_minigame_1013_icon_1_022_001", 3000, "vo_minigame_1013_icon_2_022_001", "はっはっは！\n任せろ！", "任せてくれたまえ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (1, 8, 15, 0, 10, "vo_minigame_1013_icon_1_023_001", 3000, "vo_minigame_1013_icon_2_023_001", "どんどんいくわよ", "ほな、いきまひょか");
